1	// Quote constants
2	const PROCESSING_FEE = 5;
3	const DEFAULT_BASE_PREMIUM = 100;
4	const CURSE_SURCHARGE_RATE = 0.5;
5	const FIRST_INSURANCE_RATE = 0.1;
6	const HIGH_ENCHANTMENT_RATE = 0.3;
7	const HIGH_ENCHANTMENT_THRESHOLD = 5;
8	const LOYALTY_DISCOUNT_RATE = 0.2;
9	const LOYALTY_THRESHOLD_YEARS = 2;
10	const FOLLOW_UP_DISCOUNT_RATE = 0.15;
11	
12	// Claim constants
13	const DEDUCTIBLE = 100;
14	const CAP_MULTIPLIER = 2;
15	const DEFAULT_INSURANCE_VALUE = 1000;
16	const HIGH_ENCHANTMENT_PAYOUT_THRESHOLD = 8;
17	const HIGH_ENCHANTMENT_PAYOUT_RATE = 0.5;
18	const FULL_PAYOUT_RATE = 1;
19	
20	type QuoteItem = { type: string; material?: string; enchantment?: number; cursed?: boolean };
21	type Damage = { itemType: string; amount: number };
22	type Incident = { cause: string; damages: Damage[] };
23	type Step =
24	  | { op: "quote"; items: QuoteItem[] }
25	  | { op: "claim"; policy: number; incident: Incident };
26	type Customer = { yearsWithMHPCO: number };
27	type Scenario = { customer: Customer; steps: Step[] };
28	
29	const BLOCK_TYPE = "block";
30	const BLOCK_OF_THREE_BASE = 60;
31	const BLOCK_SIZE = 3;
32	
33	const BASE_PREMIUM_BY_TYPE: Record<string, number> = {
34	  amulet: 60,
35	  rune: 25,
36	  moonstone: 25,
37	  [BLOCK_TYPE]: BLOCK_OF_THREE_BASE,
38	};
39	const BLOCK_TYPES = new Set(["rune", "moonstone"]);
40	
41	const INSURANCE_VALUE_BY_TYPE: Record<string, number> = {
42	  sword: 1000,
43	  amulet: 600,
44	  staff: 800,
45	  potion: 400,
46	  rune: 250,
47	  moonstone: 250,
48	};
49	
50	const KNOWN_ITEM_TYPES = new Set(Object.keys(INSURANCE_VALUE_BY_TYPE));
51	
52	const assertKnownItemType = (item: QuoteItem): void => {
53	  if (!KNOWN_ITEM_TYPES.has(item.type)) {
54	    throw new Error(`Unknown item type: ${item.type}`);
55	  }
56	};
57	
58	const insuranceValueForItem = (item: QuoteItem): number =>
59	  INSURANCE_VALUE_BY_TYPE[item.type] ?? DEFAULT_INSURANCE_VALUE;
60	
61	const basePremiumForItem = (item: QuoteItem): number =>
62	  BASE_PREMIUM_BY_TYPE[item.type] ?? DEFAULT_BASE_PREMIUM;
63	
64	const groupByType = (items: QuoteItem[]): Map<string, QuoteItem[]> =>
65	  items.reduce((groups, item) => {
66	    const group = groups.get(item.type) ?? [];
67	    return groups.set(item.type, [...group, item]);
68	  }, new Map<string, QuoteItem[]>());
69	
70	const isHighEnchantment = (item: QuoteItem): boolean =>
71	  (item.enchantment ?? 0) >= HIGH_ENCHANTMENT_THRESHOLD;
72	
73	const itemSurchargeRate = (item: QuoteItem): number =>
74	  (item.cursed ? CURSE_SURCHARGE_RATE : 0) +
75	  (isHighEnchantment(item) ? HIGH_ENCHANTMENT_RATE : 0) +
76	  FIRST_INSURANCE_RATE;
77	
78	const itemPremium = (item: QuoteItem): number => {
79	  const base = basePremiumForItem(item);
80	  return base + base * itemSurchargeRate(item);
81	};
82	
83	const isBlockGroup = (type: string, group: QuoteItem[]): boolean =>
84	  BLOCK_TYPES.has(type) && group.length === BLOCK_SIZE;
85	
86	const billingItems = (items: QuoteItem[]): QuoteItem[] =>
87	  [...groupByType(items)].flatMap(([type, group]) =>
88	    isBlockGroup(type, group) ? [{ type: BLOCK_TYPE }] : group,
89	  );
90	
91	const sumBy = <T>(items: T[], fn: (item: T) => number): number =>
92	  items.reduce((total, item) => total + fn(item), 0);
93	
94	const policyDiscountRate = (customer: Customer, quoteIndex: number): number =>
95	  (customer.yearsWithMHPCO >= LOYALTY_THRESHOLD_YEARS ? LOYALTY_DISCOUNT_RATE : 0) +
96	  (quoteIndex > 0 ? FOLLOW_UP_DISCOUNT_RATE : 0);
97	
98	type QuoteResult = { premium: number };
99	type ClaimResult = { payout: number; remainingCap: number };
100	type StepResult = QuoteResult | ClaimResult;
101	
102	type Policy = { items: QuoteItem[]; remainingCap: number };
103	
104	const quoteStep = (
105	  customer: Customer,
106	  quoteIndex: number,
107	  items: QuoteItem[],
108	): QuoteResult => {
109	  items.forEach(assertKnownItemType);
110	  const billables = billingItems(items);
111	  const policyBase = sumBy(billables, basePremiumForItem);
112	  const subtotal = sumBy(billables, itemPremium);
113	  const discount = policyBase * policyDiscountRate(customer, quoteIndex);
114	  return { premium: Math.ceil(subtotal - discount + PROCESSING_FEE) };
115	};
116	
117	const payoutRate = (item: QuoteItem | undefined): number =>
118	  (item?.enchantment ?? 0) >= HIGH_ENCHANTMENT_PAYOUT_THRESHOLD
119	    ? HIGH_ENCHANTMENT_PAYOUT_RATE
120	    : FULL_PAYOUT_RATE;
121	
122	const findInsuredItem = (policy: Policy, itemType: string): QuoteItem | undefined =>
123	  policy.items.find((it) => it.type === itemType);
124	
125	const reimbursementForDamage = (policy: Policy, dmg: Damage): number =>
126	  dmg.amount * payoutRate(findInsuredItem(policy, dmg.itemType)) - DEDUCTIBLE;
127	
128	const totalReimbursement = (policy: Policy, incident: Incident): number =>
129	  sumBy(incident.damages, (dmg) => reimbursementForDamage(policy, dmg));
130	
131	const claimStep = (policy: Policy, incident: Incident): { result: ClaimResult; policy: Policy } => {
132	  const { remainingCap: cap } = policy;
133	  const payout = Math.floor(Math.min(totalReimbursement(policy, incident), cap));
134	  const remainingCap = cap - payout;
135	  return {
136	    result: { payout, remainingCap },
137	    policy: { ...policy, remainingCap },
138	  };
139	};
140	
141	const policyFromItems = (items: QuoteItem[]): Policy => ({
142	  items,
143	  remainingCap: sumBy(items, insuranceValueForItem) * CAP_MULTIPLIER,
144	});
145	
146	type ScenarioState = {
147	  results: StepResult[];
148	  quoteIndex: number;
149	  policies: Record<number, Policy>;
150	};
151	
152	const initialState: ScenarioState = { results: [], quoteIndex: 0, policies: {} };
153	
154	const applyQuote = (
155	  customer: Customer,
156	  state: ScenarioState,
157	  items: QuoteItem[],
158	  policyId: number,
159	): ScenarioState => ({
160	  ...state,
161	  results: [...state.results, quoteStep(customer, state.quoteIndex, items)],
162	  quoteIndex: state.quoteIndex + 1,
163	  policies: { ...state.policies, [policyId]: policyFromItems(items) },
164	});
165	
166	const applyClaim = (
167	  state: ScenarioState,
168	  policyId: number,
169	  incident: Incident,
170	): ScenarioState => {
171	  const { result, policy } = claimStep(state.policies[policyId], incident);
172	  return {
173	    ...state,
174	    results: [...state.results, result],
175	    policies: { ...state.policies, [policyId]: policy },
176	  };
177	};
178	
179	const applyStep = (
180	  customer: Customer,
181	  state: ScenarioState,
182	  step: Step,
183	  index: number,
184	): ScenarioState =>
185	  step.op === "quote"
186	    ? applyQuote(customer, state, step.items, index)
187	    : applyClaim(state, step.policy, step.incident);
188	
189	export const runScenario = (scenario: unknown): unknown => {
190	  const { customer, steps } = scenario as Scenario;
191	  const { results } = steps.reduce(
192	    (state, step, index) => applyStep(customer, state, step, index),
193	    initialState,
194	  );
195	  return { results };
196	};
